// Function to do a binary search on a sorted array
int binarySearch(const std::vector<int>& arr, int target) {
    int low = 0;
    int high = arr.size() - 1;

    while (low <= high) {
        // Find the middle index
        int mid = (low + high) / 2;

        // Check if the element is present at the middle index
        if (arr[mid] == target) {
            return mid;
        }

        // If the element is smaller than the middle element, then it can only be present in the left subarray
        if (arr[mid] > target) {
            high = mid - 1;
        } else {
            // If the element is greater than the middle element, then it can only be present in the right subarray
            low = mid + 1;
        }
    }

    // If we reach here, the element is not present in the array
    return -1;
}

